const chunks = $json.chunks || [];

return chunks.map(c => ({
  json: {
    fileName: $json.fileName,
    filePath: $json.filePath,
    chunk_index: c.chunk_index,
    chunk_text: c.text
  }
}));

// Initiale Sammelstruktur
let result = {
  "Firma": null,
  "Art des Jobs": null,
  "Mitgebrachte Kenntnisse und Lehrveranstaltungen": [],
  "Fehlende Kenntnisse und Lehrveranstaltungen": []
};

for (const item of items) {
  const j = item.json;

  // Firma: ersten nicht-null Wert nehmen
  if (!result.Firma && j.Firma) {
    result.Firma = j.Firma;
  }

  // Art des Jobs: ersten nicht-null Wert nehmen
  if (!result["Art des Jobs"] && j["Art des Jobs"]) {
    result["Art des Jobs"] = j["Art des Jobs"];
  }

  // Mitgebrachte Kenntnisse sammeln
  if (Array.isArray(j["Mitgebrachte Kenntnisse und Lehrveranstaltungen"])) {
    result["Mitgebrachte Kenntnisse und Lehrveranstaltungen"].push(
      ...j["Mitgebrachte Kenntnisse und Lehrveranstaltungen"]
    );
  }

  // Fehlende Kenntnisse sammeln
  if (Array.isArray(j["Fehlende Kenntnisse und Lehrveranstaltungen"])) {
    result["Fehlende Kenntnisse und Lehrveranstaltungen"].push(
      ...j["Fehlende Kenntnisse und Lehrveranstaltungen"]
    );
  }

  // Abschnitt gefunden → OR-Verknüpfung
  if (j.kenntnisse_abschnitt_gefunden === true) {
    result.kenntnisse_abschnitt_gefunden = true;
  }
}

// Duplikate entfernen
result["Mitgebrachte Kenntnisse und Lehrveranstaltungen"] = [
  ...new Set(result["Mitgebrachte Kenntnisse und Lehrveranstaltungen"])
];

result["Fehlende Kenntnisse und Lehrveranstaltungen"] = [
  ...new Set(result["Fehlende Kenntnisse und Lehrveranstaltungen"])
];

// Leere Arrays optional auf null setzen (falls du das willst)
if (result["Mitgebrachte Kenntnisse und Lehrveranstaltungen"].length === 0) {
  result["Mitgebrachte Kenntnisse und Lehrveranstaltungen"] = null;
}

if (result["Fehlende Kenntnisse und Lehrveranstaltungen"].length === 0) {
  result["Fehlende Kenntnisse und Lehrveranstaltungen"] = null;
}

// Als einzelnes Item zurückgeben
return [
  {
    json: result
  }
];

let obj = $json;
if (typeof $json.output === "string") {
  try {
    let clean = $json.output
      .replace(/<think>[\s\S]*?<\/think>/g, "")
      .replace(/```json/g, "")
      .replace(/```/g, "")
      .trim();
    obj = JSON.parse(clean);
  } catch (e) {
    return [{ json: { ...$json, rag_query: "" } }];
  }
}
const extracted = obj.extracted;
let rag_query = "";
if (Array.isArray(extracted) && extracted.length > 0) {
  rag_query = extracted
    .map(s => (typeof s === "string" ? s.trim() : ""))
    .filter(s => s.length > 0)
    .join(", ");
}
return [
  {
    json: {
      ...obj,
      rag_query,
    },
  },
];

// Input: items from Supabase RPC (each item.json has: id, content, score)
// Output: ONE item with a single text field `candidates_text` for the LLM

const items = $input.all();

const rows = items
  .map(i => i.json)
  .filter(r => r && r.id);

const seen = new Set();
const unique = [];

for (const r of rows) {
  if (seen.has(r.id)) continue;
  seen.add(r.id);
  unique.push({
    id: r.id,
    score: typeof r.score === "number" ? r.score : null,
    content: typeof r.content === "string" ? r.content : "",
  });
}

// Build a compact text block for the LLM
const candidates_text = unique
  .map((m, idx) => {
    const scoreStr = m.score === null ? "n/a" : m.score.toFixed(4);
    // keep content reasonably short (avoid token bloat)
    const contentShort = m.content.replace(/\s+/g, " ").slice(0, 400);
    return `#${idx + 1}\nID: ${m.id}\nScore: ${scoreStr}\nContent: ${contentShort}`;
  })
  .join("\n\n---\n\n");

return [
  {
    json: {
      candidates_text,
      // optional: keep also structured data if you still want it
      candidates_count: unique.length,
    },
  },
];

