const items = $input.all();

const result = {
  Firma: null,
  "Art des Jobs": null,
  "Mitgebrachte Kenntnisse und Lehrveranstaltungen": null,
  "Fehlende Kenntnisse und Lehrveranstaltungen": null,
};

for (const item of items) {
  const json = item.json;

  if (json.Firma !== undefined) {
    result.Firma = json.Firma;
  }

  if (json["Art des Jobs"] !== undefined) {
    result["Art des Jobs"] = json["Art des Jobs"];
  }

  if (json["Mitgebrachte Kenntnisse und Lehrveranstaltungen"] !== undefined) {
    result["Mitgebrachte Kenntnisse und Lehrveranstaltungen"] =
      json["Mitgebrachte Kenntnisse und Lehrveranstaltungen"];
  }

  if (json["Fehlende Kenntnisse und Lehrveranstaltungen"] !== undefined) {
    result["Fehlende Kenntnisse und Lehrveranstaltungen"] =
      json["Fehlende Kenntnisse und Lehrveranstaltungen"];
  }
}

for (const key of Object.keys(result)) {
  if (Array.isArray(result[key]) && result[key].length === 0) {
    result[key] = null;
  }
}

return [
  {
    json: result
  }
];

